// Check if a user is online based on active sessions
async function isUserOnline(email, env) {
  const query = 'SELECT COUNT(*) as count FROM sessions WHERE email = ? AND active = 1 AND last_active_at > ?';
  try {
    const recentThreshold = Date.now() - 5000; // Consider online if active within last 5 seconds
    const result = await env.user_data.prepare(query).bind(email, recentThreshold).first();
    return result.count > 0;
  } catch (err) {
    console.error('Error checking user online status:', err);
    return false;
  }
}


function parseSessionId(cookies) {
  if (!cookies) return null;
  const match = cookies.match(/session_id=([^;]+)/);
  return match ? match[1] : null;
}

// Helper function to escape characters for SQLite LIKE
function escapeSqliteLike(str) {
  // Replace '%' with '\%' and '_' with '\_'
  return str.replace(/%/g, '\\%').replace(/_/g, '\\_');
}


