// --- Background VPN/Proxy Check ---
async function runVpnCheckInBackground(request, env, loggedInUserEmail) {
  const clientIp = request.headers.get('cf-connecting-ip');
  const CHECK_COOLDOWN_MS = 2 * 60 * 1000; // 2 minutes in milliseconds
  // Check for recent VPN check in the database
  let shouldPerformCheck = true;
  if (loggedInUserEmail || clientIp) {
    const recentCheckQuery = `
      SELECT check_time
      FROM vpn_checks
      WHERE ${loggedInUserEmail ? 'user_email = ?' : 'client_ip = ?'}
      ORDER BY check_time DESC
      LIMIT 1
    `;
    try {
      const bindValue = loggedInUserEmail || clientIp;
      const recentCheck = await env.user_data.prepare(recentCheckQuery).bind(bindValue).first();
      if (recentCheck && recentCheck.check_time) {
        const timeSinceLastCheck = Date.now() - recentCheck.check_time;
        if (timeSinceLastCheck < CHECK_COOLDOWN_MS) {
          shouldPerformCheck = false; // Skip check if within cooldown
        }
      }
    } catch (err) {
      console.error('Error checking recent VPN check:', err);
      // Proceed with check if query fails to avoid blocking
    }
  }

  // Initialize result object
  let result = {
    client_ip: clientIp,
    user_email: loggedInUserEmail || null,
    asn: null,
    range: null,
    provider: null,
    organisation: null,
    continent: null,
    continentcode: null,
    country: null,
    isocode: null,
    region: null,
    regioncode: null,
    timezone: null,
    city: null,
    latitude: null,
    longitude: null,
    proxy: null,
    type: null,
    latency: null,
    check_time: Date.now(),
  };

  // Perform VPN check only if needed
  if (shouldPerformCheck) {
  try {
    // Use proxycheck.io to check IP
    const apiKey = "YOUR_PROXYCHECK_API_KEY"; // Replace with your proxycheck.io API key
    const ipCheckUrl = `http://proxycheck.io/v2/${clientIp}?key=${apiKey}&vpn=1&asn=1`;
    const ipResponse = await fetch(ipCheckUrl, {
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) Chrome/58.0.3029.110'
      }
    });

    if (!ipResponse.ok) {
      throw new Error(`IP check failed, status: ${ipResponse.status}`);
    }

    const ipData = await ipResponse.json();
    const ipInfo = ipData[clientIp] || {};

    // Extract fields from proxycheck.io response
    result.asn = ipInfo.asn || null;
    result.range = ipInfo.range || null;
    result.provider = ipInfo.provider || null;
    result.organisation = ipInfo.organisation || null;
    result.continent = ipInfo.continent || null;
    result.continentcode = ipInfo.continentcode || null;
    result.country = ipInfo.country || null;
    result.isocode = ipInfo.isocode || null;
    result.region = ipInfo.region || null;
    result.regioncode = ipInfo.regioncode || null;
    result.timezone = ipInfo.timezone || null;
    result.city = ipInfo.city || null;
    result.latitude = ipInfo.latitude ? parseFloat(ipInfo.latitude) : null;
    result.longitude = ipInfo.longitude ? parseFloat(ipInfo.longitude) : null;
    result.proxy = ipInfo.proxy || null;
    result.type = ipInfo.type || null;

    // Latency test
    const startTime = Date.now();
    const timeoutPromise = new Promise(resolve => setTimeout(resolve, 2000));
    await Promise.race([
      fetch(`https://${clientIp}`, { method: 'HEAD' }).catch(() => {}),
      timeoutPromise
    ]);
    result.latency = Date.now() - startTime;

  // Store results in database
  const query = `
    INSERT INTO vpn_checks (
      client_ip, user_email, asn, range, provider, organisation, continent, continentcode,
      country, isocode, region, regioncode, timezone, city, latitude, longitude,
      proxy, type, latency, check_time
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `;
  try {
    await env.user_data.prepare(query).bind(
      result.client_ip,
      result.user_email,
      result.asn,
      result.range,
      result.provider,
      result.organisation,
      result.continent,
      result.continentcode,
      result.country,
      result.isocode,
      result.region,
      result.regioncode,
      result.timezone,
      result.city,
      result.latitude,
      result.longitude,
      result.proxy,
      result.type,
      result.latency,
      result.check_time
    ).run();
  } catch (dbError) {
    console.error(`Database error storing VPN check: ${dbError.message}`);
  }
}catch (error) {
  console.error(`VPN check error: ${error.message}`);
  // Store minimal result with error context
  const errorInsertQuery = `
    INSERT INTO vpn_checks (client_ip, user_email, check_time)
    VALUES (?, ?, ?)
  `;
  try {
    await env.user_data.prepare(errorInsertQuery).bind(
      result.client_ip,
      result.user_email,
      result.check_time
    ).run();
  } catch (dbError) {
    console.error(`Database error storing minimal VPN check: ${dbError.message}`);
  }
}
}

return result;
}

