// New handler to delete the product image
async function handleAdminDeleteProductImage(request, env) {
  if (request.method !== 'POST') {
      return new Response('Method Not Allowed', { status: 405 });
  }

  try {
      const { id } = await request.json();
      if (!id) {
          return new Response('Missing product ID', { status: 400 });
      }

      const query = 'UPDATE products SET image = NULL WHERE document_id = ?';
      await env.user_info.prepare(query).bind(id).run();

      return new Response('Product image deleted successfully', { status: 200 });
  } catch (err) {
      console.error("Error deleting product image:", err);
      return new Response('Error deleting product image: ' + err.message, { status: 500 });
  }
}


// handleAdminUpdateProduct (Modified)
async function handleAdminUpdateProduct(request, env) {
  if (request.method !== 'POST') {
      return new Response('Method Not Allowed', { status: 405 });
  }

  try {
      const formData = await request.formData();
      const document_id = formData.get('document_id');
      const name = formData.get('name');
      const price = formData.get('price');
      const description = formData.get('description');
      const barcode_id = formData.get('barcode_id');
      const barcode = formData.get('barcode');
      const status = formData.get('status');
      const quantity = parseInt(formData.get('quantity'), 10); // NEW: Get quantity
      const imageFile = formData.get('image');
      const deleteImage = formData.get('deleteImage') === 'true';

      // MODIFIED: Check quantity and ensure it's a valid number
      if (!document_id || !name || !price || !description || !barcode_id || !barcode || !status || isNaN(quantity)) {
          return new Response('Missing required fields or invalid quantity', { status: 400 });
      }

      // MODIFIED: Add quantity to the UPDATE query
      let updateQuery = 'UPDATE products SET name = ?, price = ?, description = ?, barcode_id = ?, barcode = ?, status = ?, quantity = ?';
      const bindValues = [name, price, description, barcode_id, barcode, status, quantity];

      if (deleteImage) {
          updateQuery += ', image = NULL';
      } else if (imageFile && imageFile.size > 0) {
          const arrayBuffer = await imageFile.arrayBuffer();
          const base64Image = btoa(
              new Uint8Array(arrayBuffer).reduce((data, byte) => data + String.fromCharCode(byte), '')
          );
          const imageDataUrl = `data:${imageFile.type};base64,${base64Image}`;
          updateQuery += ', image = ?';
          bindValues.push(imageDataUrl);
      }

      updateQuery += ' WHERE document_id = ?';
      bindValues.push(document_id);

      await env.user_info.prepare(updateQuery).bind(...bindValues).run();

      const redirectUrl = new URL('/admin', request.url);
      return Response.redirect(redirectUrl.toString(), 302);
  } catch (error) {
      console.error('Error updating product:', error);
      return new Response('Error updating product: ' + error.message, { status: 500 });
  }
}

async function updateProductInDatabase(document_id, name, price, description, barcode_id, barcode, status, env) {
  const query = `
      UPDATE products
      SET name = ?, price = ?, description = ?, barcode_id = ?, barcode = ?, status = ?
      WHERE document_id = ?
  `;
  try {
      await env.user_info.prepare(query)
          .bind(name, price, description, barcode_id, barcode, status, document_id)
          .run();
  } catch (error) {
      console.error('Error updating product in database:', error);
      throw error;
  }
}

async function fetchBorrowingRecords(env, userEmail = null) {
  let query = `
      SELECT
          br.id,
          br.user_email,
          br.document_id,
          br.borrow_time,
          br.return_time,
          br.latitude,
          br.longitude,
          p.name AS product_name,
          p.image AS product_image
      FROM
          borrowing_records br
      JOIN
          products p ON br.document_id = p.document_id
  `;
  let bindValues = [];
  if (userEmail) {
      query += ` WHERE br.user_email = ?`;
      bindValues.push(userEmail);
  }
  query += ` ORDER BY br.borrow_time DESC`;

  try {
    const { results } = await env.user_info.prepare(query).bind(...bindValues).all();

    // Convert coordinates → human-readable place
    const enrichedResults = await Promise.all(results.map(async (record) => {
      if (record.latitude && record.longitude) {
        record.location_name = await getLocationName(record.latitude, record.longitude);
      } else {
        record.location_name = 'Unknown Location';
      }
      return record;
    }));

    return enrichedResults;
  } catch (err) {
    console.error("Error fetching borrowing records:", err);
    return [];
  }
}


// handleBorrowItem (MODIFIED to use global borrow limit from DB)
async function handleBorrowItem(request, env, loggedInUserEmail, userRole) {
  if (request.method !== 'POST') {
      return new Response('Method Not Allowed', { status: 405 });
  }
  if (!loggedInUserEmail) {
      return new Response('Authentication required', { status: 401 });
  }

  // --- NEW: Fetch MAX_DAILY_BORROWS from DB ---
  const MAX_DAILY_BORROWS = await getGlobalSetting(env, 'max_daily_borrows', 10); // Default to 10 if not found
  // --- END NEW ---

  /*
  if (userRole === 'superadmin') {
      console.log(`SUPERADMIN: ${loggedInUserEmail} is a superadmin, bypassing daily borrow limit.`);
  } else {
  */
      const userQuery = 'SELECT status, approval_status FROM users WHERE email = ?';
      const user = await env.user_data.prepare(userQuery).bind(loggedInUserEmail).first();

      if (user.approval_status === 'pending') {
          return new Response(JSON.stringify({ message: 'Your account is pending approval and cannot borrow items.' }), { status: 403, headers: { 'Content-Type': 'application/json' } });
      }
      if (user.approval_status === 'rejected') {
          return new Response(JSON.stringify({ message: 'Your account has been rejected and cannot borrow items.' }), { status: 403, headers: { 'Content-Type': 'application/json' } });
      }

      if (user.status === 'blocked') {
          return new Response('Your account has been blocked by an admin.', { status: 403 });
      }

      const today = new Date();
      const borrowDate = today.toISOString().split('T')[0];

      const currentBorrowCountQuery = 'SELECT borrow_count FROM daily_borrows WHERE user_email = ? AND borrow_date = ?';
      const currentBorrowResult = await env.user_data.prepare(currentBorrowCountQuery).bind(loggedInUserEmail, borrowDate).first();
      let currentCount = 0;
      if (currentBorrowResult) {
          currentCount = currentBorrowResult.borrow_count;
      }
  /*
  }
  */

  try {
      const formData = await request.formData();
      const document_id = formData.get('document_id');
      const quantityToBorrow = parseInt(formData.get('quantity_to_borrow'), 10);
      const latitude = formData.get('latitude');
      const longitude = formData.get('longitude');

      if (isNaN(quantityToBorrow) || quantityToBorrow <= 0) {
          return new Response('Invalid quantity to borrow. Quantity must be a positive number.', { status: 400 });
      }
      if (!document_id || !latitude || !longitude) {
          return new Response('Missing required fields (document_id, latitude, longitude)', { status: 400 });
      }

      const productQuery = 'SELECT document_id, name, status, quantity FROM products WHERE document_id = ?';
      const product = await env.user_info.prepare(productQuery).bind(document_id).first();

      if (!product) {
          return new Response('Product not found.', { status: 404 });
      }

      if (product.quantity < quantityToBorrow) {
          return new Response(`Not enough stock. Only ${product.quantity} of "${product.name}" available.`, { status: 409 });
      }

      // Validate against daily borrow limit *after* stock check
      if (currentCount + quantityToBorrow > MAX_DAILY_BORROWS) {
          return new Response(`Borrow limit reached. You can only borrow ${MAX_DAILY_BORROWS - currentCount} more items today due to your daily limit.`, { status: 403 });
      }

      const newProductQuantity = product.quantity - quantityToBorrow;
      let newProductStatus = product.status;
      if (newProductQuantity <= 0) {
          newProductStatus = 'Borrowed';
      }

      const updateProductQuery = 'UPDATE products SET quantity = ?, status = ? WHERE document_id = ?';
      await env.user_info.prepare(updateProductQuery).bind(newProductQuantity, newProductStatus, document_id).run();

      const insertBorrowQuery = 'INSERT INTO borrowing_records (user_email, document_id, product_name, borrow_time, return_time, latitude, longitude) VALUES (?, ?, ?, ?, NULL, ?, ?)';
      for (let i = 0; i < quantityToBorrow; i++) {
          await env.user_info.prepare(insertBorrowQuery).bind(loggedInUserEmail, product.document_id, product.name, Date.now(), latitude, longitude).run();
      }

      const upsertBorrowCountQuery = `
    INSERT INTO daily_borrows (user_email, borrow_date, borrow_count)
    VALUES (?, ?, ?)
    ON CONFLICT(user_email, borrow_date) DO UPDATE SET borrow_count = daily_borrows.borrow_count + ?;
`;
await env.user_data.prepare(upsertBorrowCountQuery).bind(loggedInUserEmail, borrowDate, quantityToBorrow, quantityToBorrow).run();
// NEW CODE START: Create notification for successful borrow with return date
const escapedProductNameForNotification = escapeHtml(product.name);

// Fetch username from DB
const userQueryName = 'SELECT username FROM users WHERE email = ?';
const userData = await env.user_data.prepare(userQueryName).bind(loggedInUserEmail).first();
const studentName = userData?.username ? escapeHtml(userData.username) : 'Unknown Student';

// Calculate return (due) date = borrow time + 7 days
const borrowTime = new Date();
const returnTime = new Date(borrowTime.getTime() + 7 * 24 * 60 * 60 * 1000);
const formattedReturnTime = returnTime.toLocaleString('en-MY', { timeZone: 'Asia/Kuala_Lumpur' });

// Create notification message
const message = `You (Student ${studentName}) have successfully borrowed "${escapedProductNameForNotification}". Please return it on time. Return date: ${formattedReturnTime}`;

await createNotification(env, loggedInUserEmail, message);
// NEW CODE END

return new Response(renderBorrowSuccessPage(product.name, quantityToBorrow, newProductQuantity), {
    headers: { 'Content-Type': 'text/html' },
    status: 200,
});

  } catch (err) {
      console.error('Error borrowing item:', err);
      return new Response('Error borrowing item: ' + err.message, { status: 500 });
  }
}


// handleReturnItem (Modified - Fetch and filter in JS, then update by ID)
async function handleReturnItem(request, env) {
  if (request.method !== 'POST') {
      return new Response('Method Not Allowed', { status: 405 });
  }

  const formData = await request.formData();
  const recordId = formData.get('record_id');

  if (!recordId) {
      return new Response('Missing record ID', { status: 400 });
  }

  try {
      // Fetch user_email and product_name along with other record details
      const checkQuery = 'SELECT br.document_id, br.return_time, br.user_email, p.name as product_name FROM borrowing_records br JOIN products p ON br.document_id = p.document_id WHERE br.id = ?';
      const record = await env.user_info.prepare(checkQuery).bind(recordId).first();

      if (!record) {
          return new Response('Borrowing record not found', { status: 404 });
      }
      if (record.return_time) {
          return new Response('This item has already been returned.', { status: 409 });
      }

      const returnTime = Date.now();
      const query = 'UPDATE borrowing_records SET return_time = ? WHERE id = ?';
      await env.user_info.prepare(query).bind(returnTime, recordId).run();

      // Increment quantity
      const updateProductQuantityQuery = 'UPDATE products SET quantity = quantity + 1 WHERE document_id = ?';
      await env.user_info.prepare(updateProductQuantityQuery).bind(record.document_id).run();

      // Update product status to 'Available' if it was 'Borrowed' (and now quantity > 0)
      const updateProductStatusQuery = 'UPDATE products SET status = ? WHERE document_id = ? AND status = ?';
      await env.user_info.prepare(updateProductStatusQuery).bind('Available', record.document_id, 'Borrowed').run();

      // NEW LOGIC: Fetch and filter notifications in JavaScript, then update by ID
      if (record.user_email && record.product_name) {
          // Construct the quoted product name for matching in messages
          const productNameInQuotes = `"${record.product_name}"`;

          // 1. Fetch all unread notifications for the user
          const fetchNotificationsQuery = `
              SELECT id, message
              FROM notifications
              WHERE user_email = ? AND read = 0
          `;
          const { results: userNotifications } = await env.user_data.prepare(fetchNotificationsQuery)
              .bind(record.user_email)
              .all();

          const notificationsToMarkRead = [];

          // Define message patterns to match
          // Note: "You have successfully borrowed..." might have a variable timestamp suffix, so .includes() is safer.
          // Reminders and Overdue alerts have consistent prefixes, so .startsWith() is fine.
          const borrowedMessagePartial = `You have successfully borrowed ${productNameInQuotes}. Please return it on time.`;
          const reminderMessagePrefix = `🔔 Reminder: Your borrowed item ${productNameInQuotes}`;
          const overdueMessagePrefix = `⚠️ Overdue Alert: Your borrowed item ${productNameInQuotes}`;

          // 2. Filter notifications in JavaScript
          for (const notif of userNotifications) {
              if (notif.message.includes(borrowedMessagePartial) ||
                  notif.message.startsWith(reminderMessagePrefix) ||
                  notif.message.startsWith(overdueMessagePrefix)) {
                  notificationsToMarkRead.push(notif.id);
              }
          }

          // 3. Mark matching notifications as read by ID
          if (notificationsToMarkRead.length > 0) {
              // Create a placeholder string for the IN clause (e.g., ?, ?, ?)
              const placeholders = notificationsToMarkRead.map(() => '?').join(', ');
              const updateNotificationsQuery = `
                  UPDATE notifications
                  SET read = 1
                  WHERE id IN (${placeholders})
              `;
              await env.user_data.prepare(updateNotificationsQuery)
                  .bind(...notificationsToMarkRead) // Spread the array as arguments
                  .run();
              console.log(`Marked ${notificationsToMarkRead.length} notifications as read for ${record.product_name} for user ${record.user_email}.`);
          } else {
              console.log(`No specific notifications to mark as read found for ${record.product_name} for user ${record.user_email}.`);
          }

          // Optional: Send a "Thank you for returning" notification (This one is new and will appear)
          await createNotification(env, record.user_email, `Thank you for returning "${record.product_name}".`);
      }

      const redirectUrl = new URL('/system', request.url);
      return Response.redirect(redirectUrl.toString(), 302);
  } catch (err) {
      console.error('Error returning item:', err);
      return new Response('Error returning item: ' + err.message, { status: 500 });
  }
}

async function handleComments(request, env, loggedInUserEmail, userRole) { // MODIFIED: Added userRole
  if (!loggedInUserEmail) {
    return new Response(renderAccessDeniedPage(), {
      headers: { 'Content-Type': 'text/html' },
      status: 403,
    });
  }

  // NEW: Super Admin Bypass
  if (userRole === 'superadmin') {
    console.log(`SUPERADMIN: User ${loggedInUserEmail} is superadmin. Allowing comments access.`);
    // Continue directly to fetching comments
  } else {
    // Existing checks for non-superadmin users
    const userQuery = 'SELECT approval_status FROM users WHERE email = ?';
    const user = await env.user_data.prepare(userQuery).bind(loggedInUserEmail).first();
    if (user.approval_status === 'pending') {
        return new Response(renderPendingApprovalPage(), { headers: { 'Content-Type': 'text/html' }, status: 403 });
    }
    if (user.approval_status === 'rejected') {
        return new Response(renderRejectedApprovalPage(), { headers: { 'Content-Type': 'text/html' }, status: 403 });
    }
  }

  if (request.method === 'GET') {
    const comments = await fetchComments(env);
    return new Response(renderCommentsPage(comments, loggedInUserEmail), {
      headers: { 'Content-Type': 'text/html' },
    });
  }
  return new Response('Method Not Allowed', { status: 405 });
}

