async function handleSendMessage(request, env, loggedInUserEmail, userRole) { // MODIFIED: Added userRole
  if (!loggedInUserEmail) {
    return new Response('Unauthorized', { status: 401 });
  }

  // NEW: Super Admin Bypass
  if (userRole === 'superadmin') {
    console.log(`SUPERADMIN: User ${loggedInUserEmail} is superadmin. Allowing message sending.`);
    // Continue directly to sending message
  } else {
    // Existing checks for non-superadmin users
    const userQuery = 'SELECT approval_status FROM users WHERE email = ?';
    const user = await env.user_data.prepare(userQuery).bind(loggedInUserEmail).first();
    if (user.approval_status === 'pending') {
        return new Response(JSON.stringify({ message: 'Your account is pending approval and cannot send messages.' }), { status: 403, headers: { 'Content-Type': 'application/json' } });
    }
    if (user.approval_status === 'rejected') {
        return new Response(JSON.stringify({ message: 'Your account has been rejected and cannot send messages.' }), { status: 403, headers: { 'Content-Type': 'application/json' } });
    }
  }

  if (request.method !== 'POST') {
    return new Response('Method Not Allowed', { status: 405 });
  }

  try {
    const formData = await request.formData();
    const recipientEmail = formData.get('recipient_email');
    const content = formData.get('content');

    if (!recipientEmail || !content) {
      return new Response('Recipient email and message content are required', { status: 400 });
    }

    const userCheckQuery = 'SELECT COUNT(*) as count FROM users WHERE email = ?';
    const userCheckResult = await env.user_data.prepare(userCheckQuery).bind(recipientEmail).first();
    if (userCheckResult.count === 0) {
      return new Response('Recipient not found', { status: 404 });
    }

    const query = 'INSERT INTO messages (sender_email, recipient_email, content, created_at) VALUES (?, ?, ?, ?)';
    await env.user_data.prepare(query)
      .bind(loggedInUserEmail, recipientEmail, content, Date.now())
      .run();

    //const message = `New message from ${loggedInUserEmail}`;
    //await createNotification(env, recipientEmail, message);

    return new Response(JSON.stringify({ status: 'success' }), {
      headers: { 'Content-Type': 'application/json' },
      status: 200
    });
  } catch (err) {
    console.error('Error sending message:', err);
    return new Response('Error sending message: ' + err.message, { status: 500 });
  }
}

