async function fetchComments(env) {
  const query = `
    SELECT c.*, u.username 
    FROM comments c 
    JOIN users u ON c.user_email = u.email 
    ORDER BY c.created_at DESC
  `;
  try {
    const { results } = await env.user_data.prepare(query).all();
    return results || [];
  } catch (err) {
    console.error('Error fetching comments:', err);
    return [];
  }
}


async function fetchAllUsersWithStatus(env) {
  const query = 'SELECT email, username FROM users';
  try {
    const { results } = await env.user_data.prepare(query).all();
    // Add online status for each user
    const usersWithStatus = await Promise.all(
      results.map(async (user) => ({
        ...user,
        online: await isUserOnline(user.email, env),
      }))
    );
    return usersWithStatus;
  } catch (err) {
    console.error('Error fetching users with status:', err);
    return [];
  }
}

async function fetchUserMessages(env, userEmail) {
  const query = `
    SELECT m.*, u1.username as sender_username, u2.username as recipient_username
    FROM messages m
    JOIN users u1 ON m.sender_email = u1.email
    JOIN users u2 ON m.recipient_email = u2.email
    WHERE m.sender_email = ? OR m.recipient_email = ?
    ORDER BY m.created_at DESC
  `;
  try {
    const { results } = await env.user_data.prepare(query).bind(userEmail, userEmail).all();
    return results || [];
  } catch (err) {
    console.error('Error fetching user messages:', err);
    return [];
  }
}

// Function to escape HTML special characters
function escapeHtml(unsafe) {
  // 确保输入值不是 null 或 undefined。
  // 如果是，则将其视为空字符串，然后转换为字符串类型。
  // 这样，.replace() 方法将始终在一个有效的字符串上被调用。
  const str = (unsafe === null || typeof unsafe === 'undefined') ? '' : String(unsafe);
  
  return str
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#039;");
}

