                              <path d="M232,128A104,104,0,1,1,128,24,104.11,104.11,0,0,1,232,128ZM128,40a88,88,0,1,0,88,88A88.1,88.1,0,0,1,128,40ZM160,128a32,32,0,1,1-32-32A32,32,0,0,1,160,128Zm-32-16a16,16,0,1,0,16,16A16,16,0,0,0,128,112Z"></path>
