                                <path d="M208,88H168V56a40,40,0,0,0-80,0V88H48a8,8,0,0,0-8,8V216a8,8,0,0,0,8,8H208a8,8,0,0,0,8-8V96A8,8,0,0,0,208,88ZM96,56a24,24,0,0,1,48,0V88H96ZM200,208H56V104H200Z"></path>
