async function handleTwoFactorDisable(request, env, loggedInUserEmail) {
  if (request.method !== 'POST') {
    return new Response('Method Not Allowed', { status: 405 });
  }

  if (!loggedInUserEmail) {
    return new Response(renderAccessDeniedPage(), {
      headers: { 'Content-Type': 'text/html' },
      status: 403,
    });
  }

  try {
    const disableQuery = 'UPDATE users SET two_factor_enabled = FALSE, two_factor_secret = NULL WHERE email = ?';
    await env.user_data.prepare(disableQuery).bind(loggedInUserEmail).run();

    const redirectUrl = new URL('/profile', request.url);
    return Response.redirect(redirectUrl.toString(), 302);
  } catch (err) {
    console.error('Error disabling 2FA:', err);
    return new Response('Error disabling 2FA: ' + err.message, { status: 500 });
  }
}

function generateSecret() {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ234567';
  let secret = '';
  for (let i = 0; i < 16; i++) {
    secret += chars[Math.floor(Math.random() * chars.length)];
  }
  return secret;
}

async function handleAdminExport(request, env) {
  const url = new URL(request.url);
  const type = url.searchParams.get('type');

  if (type === 'users') {
    try {
      // MODIFIED: Select role as well
      const { results: users } = await env.user_data.prepare('SELECT * FROM users').all();

      let excelContent = `<?xml version="1.0"?>
<?mso-application progid="Excel.Sheet"?>
<Workbook xmlns="urn:schemas-microsoft-com:office:spreadsheet"
 xmlns:o="urn:schemas-microsoft-com:office:office"
 xmlns:x="urn:schemas-microsoft-com:office:excel"
 xmlns:ss="urn:schemas-microsoft-com:office:spreadsheet">
 <Worksheet ss:Name="Users">
  <Table>
   <Row>
    <Cell><Data ss:Type="String">ID</Data></Cell> <!-- NEW: Added ID for completeness -->
    <Cell><Data ss:Type="String">Email</Data></Cell>
    <Cell><Data ss:Type="String">Username</Data></Cell>
    <Cell><Data ss:Type="String">Role</Data></Cell> <!-- NEW COLUMN -->
    <Cell><Data ss:Type="String">Status</Data></Cell>
    <Cell><Data ss:Type="String">Approval Status</Data></Cell> <!-- NEW COLUMN -->
    <Cell><Data ss:Type="String">Warning Count</Data></Cell>
    <Cell><Data ss:Type="String">Warning Reason</Data></Cell>
    <Cell><Data ss:Type="String">2FA Enabled</Data></Cell>
   </Row>`;

      users.forEach(user => {
        const escapeXml = (str) => {
          if (!str) return '';
          return String(str)
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;')
            .replace(/'/g, '&apos;');
        };

        excelContent += `
   <Row>
    <Cell><Data ss:Type="Number">${user.id || ''}</Data></Cell> <!-- NEW: Export ID -->
    <Cell><Data ss:Type="String">${escapeXml(user.email || '')}</Data></Cell>
    <Cell><Data ss:Type="String">${escapeXml(user.username || '')}</Data></Cell>
    <Cell><Data ss:Type="String">${escapeXml(user.role || 'user')}</Data></Cell> <!-- NEW: Export Role -->
    <Cell><Data ss:Type="String">${escapeXml(user.status || 'active')}</Data></Cell>
    <Cell><Data ss:Type="String">${escapeXml(user.approval_status || 'approved')}</Data></Cell> <!-- NEW: Export Approval Status -->
    <Cell><Data ss:Type="Number">${user.warning_count || 0}</Data></Cell>
    <Cell><Data ss:Type="String">${escapeXml(user.warning_reason || '')}</Data></Cell>
    <Cell><Data ss:Type="String">${user.two_factor_enabled ? 'Yes' : 'No'}</Data></Cell>
   </Row>`;
      });

      excelContent += `
  </Table>
 </Worksheet>
</Workbook>`;

      return new Response(excelContent, {
        headers: {
          'Content-Type': 'application/vnd.ms-excel',
          'Content-Disposition': 'attachment; filename="users.xls"'
        }
      });
    } catch (error) {
      console.error('Error exporting users:', error);
      return new Response('Error exporting users: ' + error.message, { status: 500 });
    }
  } else if (type === 'products') {
    // ... (rest of products export remains unchanged)
    try {
      // Fetch all products from the database
      const { results: products } = await env.user_info.prepare('SELECT * FROM products').all();

      // Create Excel XML content
      let excelContent = `<?xml version="1.0"?>
<?mso-application progid="Excel.Sheet"?>
<Workbook xmlns="urn:schemas-microsoft-com:office:spreadsheet"
 xmlns:o="urn:schemas-microsoft-com:office:office"
 xmlns:x="urn:schemas-microsoft-com:office:excel"
 xmlns:ss="urn:schemas-microsoft-com:office:spreadsheet">
 <Worksheet ss:Name="Products">
  <Table>
   <Row>
    <Cell><Data ss:Type="String">Document ID</Data></Cell>
    <Cell><Data ss:Type="String">Name</Data></Cell>
    <Cell><Data ss:Type="String">Price</Data></Cell>
    <Cell><Data ss:Type="String">Description</Data></Cell>
    <Cell><Data ss:Type="String">Barcode ID</Data></Cell>
    <Cell><Data ss:Type="String">Barcode</Data></Cell>
    <Cell><Data ss:Type="String">Status</Data></Cell>
   </Row>`;

      products.forEach(product => {
        const escapeXml = (str) => {
          if (!str) return '';
          return String(str)
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;')
            .replace(/'/g, '&apos;');
        };

        excelContent += `
   <Row>
    <Cell><Data ss:Type="String">${escapeXml(product.document_id)}</Data></Cell>
    <Cell><Data ss:Type="String">${escapeXml(product.name)}</Data></Cell>
    <Cell><Data ss:Type="Number">${product.price || 0}</Data></Cell>
    <Cell><Data ss:Type="String">${escapeXml(product.description)}</Data></Cell>
    <Cell><Data ss:Type="String">${escapeXml(product.barcode_id)}</Data></Cell>
    <Cell><Data ss:Type="String">${escapeXml(product.barcode)}</Data></Cell>
    <Cell><Data ss:Type="String">${escapeXml(product.status)}</Data></Cell>
   </Row>`;
      });

      excelContent += `
  </Table>
 </Worksheet>
</Workbook>`;

      return new Response(excelContent, {
        headers: {
          'Content-Type': 'application/vnd.ms-excel',
          'Content-Disposition': 'attachment; filename="products.xls"'
        }
      });
    } catch (error) {
      console.error('Error exporting products:', error);
      return new Response('Error exporting products: ' + error.message, { status: 500 });
    }
  }

  return new Response('Invalid export type', { status: 400 });
}

