// handleAdminAddProduct (Modified)
async function handleAdminAddProduct(request, env) {
  if (request.method !== 'POST') {
      return new Response('Method Not Allowed', { status: 405 });
  }
  const formData = await request.formData();
  const name = formData.get('name');
  const price = formData.get('price');
  const description = formData.get('description');
  let barcode_id = formData.get('barcode_id'); // Allow modification
  let barcode = formData.get('barcode');     // Allow modification
  const quantity = parseInt(formData.get('quantity'), 10); // NEW: Get quantity
  const imageFile = formData.get('image');

  // NEW: Generate random barcode if not provided
  if (!barcode_id || barcode_id.trim() === '') { // Also check for empty string
      barcode_id = generateRandomBarcode();
      console.log(`Generated random barcode_id for new product: ${barcode_id}`);
  }
  // Ensure barcode is the same as barcode_id if barcode is not explicitly set or is empty
  if (!barcode || barcode.trim() === '') { // Also check for empty string
      barcode = barcode_id;
  }

  // MODIFIED: Check quantity and ensure it's a valid number
  if (!name || !price || !description || !barcode_id || !barcode || isNaN(quantity) || quantity < 0 || !imageFile) {
      return new Response('Missing product name, price, description, barcode ID, barcode, quantity, or image, or invalid quantity.', { status: 400 });
  }
  try {
    const arrayBuffer = await imageFile.arrayBuffer();
    const base64Image = btoa(
        new Uint8Array(arrayBuffer).reduce((data, byte) => data + String.fromCharCode(byte), '')
    );
    const imageDataUrl = `data:${imageFile.type};base64,${base64Image}`;

    // MODIFIED: Include quantity in the INSERT query
    const query = 'INSERT INTO products (name, price, description, barcode_id, barcode, image, quantity) VALUES (?, ?, ?, ?, ?, ?, ?)';
    await env.user_info.prepare(query).bind(name, price, description, barcode_id, barcode, imageDataUrl, quantity).run();
    const redirectUrl = new URL('/admin', request.url);
    return Response.redirect(redirectUrl.toString(), 302);
  } catch (err) {
      console.error("Error during adding product:", err); // Log the full error
      return new Response(`Error during adding product: ${err.message}`, { status: 500 });
  }
}

