// 在您的 handleRequest 函数中
async function handleRequest(request, env) {
  const url = new URL(request.url);
  // --- Google OAuth 路由 ---
  if (url.pathname === '/auth/google') {
    return handleGoogleLogin(request, env);
  } else if (url.pathname === '/auth/google/callback') {
    return handleGoogleCallback(request, env);
  }  
  // --- 结束 Google OAuth 路由 ---
  // ... (您的其他路由，例如 /signup, /login, /dashboard 等)
}

// 1. 处理 Google 登录发起
// 1. 处理 Google 登录发起
async function handleGoogleLogin(request, env) {
  const state = crypto.randomUUID(); // 用于防止 CSRF 攻击
  const scope = 'openid email profile'; // 请求的权限范围

  const authUrl = new URL(GOOGLE_AUTH_URL);
  authUrl.searchParams.set('client_id', env.GOOGLE_CLIENT_ID);
  authUrl.searchParams.set('redirect_uri', env.GOOGLE_REDIRECT_URI);
  authUrl.searchParams.set('response_type', 'code');
  authUrl.searchParams.set('scope', scope);
  authUrl.searchParams.set('state', state);

  console.log('DEBUG: Generated Google Auth URL sent to user:', authUrl.toString());

  const headers = new Headers();
  headers.set('Location', authUrl.toString());
  // 设置 google_oauth_state cookie，有效期 10 分钟 (增加一点时间)
  headers.set('Set-Cookie', `google_oauth_state=${state}; Path=/; HttpOnly; Secure; SameSite=Lax; Max-Age=${10 * 60}`);

  // 根据 Referer 头判断请求来源，并设置 google_flow_origin cookie
  const referer = request.headers.get('Referer');
  if (referer) {
      const refererUrl = new URL(referer);
      let originType = 'unknown'; // 默认值
      if (refererUrl.pathname === '/login') {
          originType = 'login_page';
      } else if (refererUrl.pathname === '/signup') {
          originType = 'signup_page';
      }
      // 设置一个临时 cookie 来跟踪此 Google OAuth 流程的来源，有效期 10 分钟 (增加一点时间)
      headers.append('Set-Cookie', `google_flow_origin=${originType}; Path=/; HttpOnly; Secure; SameSite=Lax; Max-Age=${10 * 60}`);
      console.log(`DEBUG: Google OAuth initiated from: ${originType}`);
  } else {
      // 如果没有 Referer，也设置一个默认的 originType，以防万一
      headers.append('Set-Cookie', `google_flow_origin=unknown; Path=/; HttpOnly; Secure; SameSite=Lax; Max-Age=${10 * 60}`);
      console.log(`DEBUG: Google OAuth initiated with unknown origin (no Referer).`);
  }


  return new Response(null, {
    status: 302,
    headers: headers,
  });
}

// 2. 处理 Google OAuth 回调
// 确保 GOOGLE_TOKEN_URL 像这样定义在您的 Worker 文件顶部或其他常量定义处
// const GOOGLE_TOKEN_URL = 'https://oauth2.googleapis.com/token';

// 2. 处理 Google OAuth 回调
async function handleGoogleCallback(request, env) {
  console.log('=== Google Callback Started ===');

  try {
    const url = new URL(request.url);
    const code = url.searchParams.get('code');

    if (!code) {
      return new Response('Missing authorization code from Google.', { status: 400 });
    }

    const redirectUri = env.GOOGLE_REDIRECT_URI;

    // Exchange code for tokens
    const tokenResponse = await fetch(GOOGLE_TOKEN_URL, {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: new URLSearchParams({
        code,
        client_id: env.GOOGLE_CLIENT_ID,
        client_secret: env.GOOGLE_CLIENT_SECRET,
        redirect_uri: redirectUri,
        grant_type: 'authorization_code',
      }),
    });

    const tokenData = await tokenResponse.json();
    if (!tokenResponse.ok || tokenData.error) {
      console.error('Token exchange failed:', tokenData);
      return new Response(`Google authentication failed: ${tokenData.error || 'Unknown error'}`, { status: 400 });
    }

    // Get user info
    const userInfoResponse = await fetch(GOOGLE_USERINFO_URL, {
      headers: { Authorization: `Bearer ${tokenData.access_token}` },
    });

    const userInfo = await userInfoResponse.json();
    if (!userInfo.email) {
      return new Response('Failed to get email from Google.', { status: 400 });
    }

    const email = userInfo.email;
    const googleId = userInfo.sub;
    const username = userInfo.name || email.split('@')[0];
    const profileImage = userInfo.picture || null;

    console.log(`Google login attempt for: ${email}`);

    // === CRITICAL: Get current user state to preserve admin decisions ===
    const existingUser = await env.user_data.prepare(`
      SELECT approval_status, password_set_status 
      FROM users WHERE email = ?
    `).bind(email).first();

    let approvalStatus = existingUser ? (existingUser.approval_status || 'pending') : 'pending';
    let passwordStatus = existingUser ? (existingUser.password_set_status || 'pending') : 'pending';

    // For new users, force pending password setup
    if (!existingUser) {
      passwordStatus = 'pending';
    }

    // Upsert user WITHOUT overwriting approval_status
    await env.user_data.prepare(`
      INSERT INTO users (
        email, google_id, username, profile_image, 
        password_set_status, approval_status, role, status, verified
      ) VALUES (?, ?, ?, ?, ?, ?, 'user', 'active', true)
      ON CONFLICT(email) DO UPDATE SET 
        google_id = COALESCE(excluded.google_id, google_id),
        username = COALESCE(excluded.username, username),
        profile_image = COALESCE(excluded.profile_image, profile_image),
        password_set_status = excluded.password_set_status,
        verified = true
        -- approval_status is intentionally omitted to preserve admin approval
    `).bind(email, googleId, username, profileImage, passwordStatus, approvalStatus).run();

    // Create / refresh session
    const sessionId = crypto.randomUUID();
    await env.user_data.prepare(`
      INSERT INTO sessions (session_id, email, active, last_active_at)
      VALUES (?, ?, 1, ?)
      ON CONFLICT(session_id) DO UPDATE SET last_active_at = ?
    `).bind(sessionId, email, Date.now(), Date.now()).run();

    // === DECIDE WHERE TO REDIRECT ===
    let redirectPath = '/pending-approval';

    // Only force set-password if password is still pending
    if (passwordStatus === 'pending' || passwordStatus === null) {
      redirectPath = '/set-password';
    } else if (approvalStatus === 'approved') {
      redirectPath = '/homepage';
    }

    const redirectUrl = new URL(redirectPath, request.url);
    if (redirectPath === '/set-password') {
      redirectUrl.searchParams.set('mandatory_setup', 'true');
    }

    const response = new Response(null, {
      status: 302,
      headers: {
        'Location': redirectUrl.toString(),
        'Set-Cookie': `session_id=${sessionId}; HttpOnly; Path=/; SameSite=Lax; Max-Age=${60 * 60 * 24 * 7}`
      }
    });

    console.log(`Google user ${email} → redirecting to ${redirectPath} (password_status=${passwordStatus}, approval=${approvalStatus})`);
    return response;

  } catch (error) {
    console.error('Error in handleGoogleCallback:', error);
    return new Response(`Google authentication failed: ${error.message}. Please try again.`, { status: 500 });
  }
}

// handleSystemRoute (MODIFIED to calculate next daily limit reset time)
async function handleSystemRoute(request, env, loggedInUserEmail, userRole) {
  if (!loggedInUserEmail) {
    return new Response('You must be logged in to access this page.', { status: 403 });
  }

  const MAX_DAILY_BORROWS = await getGlobalSetting(env, 'max_daily_borrows', 10);

  let products = [];
  let borrowingRecords = [];
  let currentBorrowCount = 0;

  try {
    products = await fetchAllProducts(env);
  } catch (err) {
    console.error('Error fetching products for system page:', err);
  }

  // --- NEW: Calculate next daily limit reset time ---
  const now = new Date();
  // For 'Asia/Kuala_Lumpur' (UTC+8)
  const kualaLumpurOffsetMs = 8 * 60 * 60 * 1000; // 8 hours in milliseconds

  // Get current time in KL timezone
  const nowInKL = new Date(now.getTime() + kualaLumpurOffsetMs);

  // Get tomorrow's date in KL timezone
  const tomorrowInKL = new Date(nowInKL);
  tomorrowInKL.setDate(nowInKL.getDate() + 1);

  // Set time to midnight (00:00:00) in KL timezone
  tomorrowInKL.setHours(0, 0, 0, 0);

  // Convert this KL midnight time back to UTC timestamp (milliseconds since epoch)
  const nextResetTimestamp = tomorrowInKL.getTime() - kualaLumpurOffsetMs;
  // --- END NEW ---

  if (userRole === 'superadmin') {
    console.log(`SUPERADMIN: User ${loggedInUserEmail} is superadmin. Fetching ALL borrowing records.`);
    borrowingRecords = await fetchBorrowingRecords(env);
    // Superadmin's borrow count is not relevant for daily limit, but we pass 0 for display consistency
    currentBorrowCount = 0;
  } else {
    const userQuery = 'SELECT status, approval_status FROM users WHERE email = ?';
    const user = await env.user_data.prepare(userQuery).bind(loggedInUserEmail).first();
    if (user.approval_status === 'pending') {
        return new Response(renderPendingApprovalPage(), { headers: { 'Content-Type': 'text/html' }, status: 403 });
    }
    if (user.approval_status === 'rejected') {
        return new Response(renderRejectedApprovalPage(), { headers: { 'Content-Type': 'text/html' }, status: 403 });
    }
    if (user.status === 'blocked') {
      const redirectUrl = new URL('/homepage', request.url);
      return Response.redirect(redirectUrl.toString(), 302);
    }
    borrowingRecords = await fetchBorrowingRecords(env, loggedInUserEmail);

    const today = new Date();
    const borrowDate = today.toISOString().split('T')[0];
    const currentBorrowCountQuery = 'SELECT borrow_count FROM daily_borrows WHERE user_email = ? AND borrow_date = ?';
    const currentBorrowResult = await env.user_data.prepare(currentBorrowCountQuery).bind(loggedInUserEmail, borrowDate).first();
    if (currentBorrowResult) {
        currentBorrowCount = currentBorrowResult.borrow_count;
    }
  }

  if (request.method === 'GET') {
    // MODIFIED: Pass nextResetTimestamp to renderSystemPage
    return new Response(renderSystemPage(products, borrowingRecords, loggedInUserEmail, currentBorrowCount, MAX_DAILY_BORROWS, nextResetTimestamp), {
      headers: { 'Content-Type': 'text/html' },
    });
  }
  return new Response('Method Not Allowed', { status: 405 });
}


// 确保 createSessionAndRedirect 函数也负责清除 google_oauth_state cookie
// 确保 createSessionAndRedirect 函数也负责清除 google_oauth_state 和 google_flow_origin cookie
async function createSessionAndRedirect(userEmail, userId, env, redirectTo = '/homepage') { // <--- 添加 redirectTo 参数及默认值
  const sessionId = crypto.randomUUID(); 
  console.log(`CREATE_SESSION_REDIRECT: Generated Session ID: ${sessionId} for user: ${userEmail}`);

  await createSession(sessionId, userEmail, env); 

  const headers = new Headers();
  // Use Secure attribute only when explicitly enabled via environment variable to support local HTTP development
  const secureAttr = env && (env.FORCE_SECURE_COOKIE === 'true' || env.FORCE_SECURE_COOKIE === true) ? '; Secure' : '';
  const sessionCookieString = `session_id=${sessionId}; Path=/; HttpOnly${secureAttr}; SameSite=Lax; Max-Age=${60 * 60 * 24 * 7}`;
  headers.set('Set-Cookie', sessionCookieString); 
  console.log(`CREATE_SESSION_REDIRECT: Setting Session Cookie: ${sessionCookieString}`);

  // 清除 google_oauth_state cookie
  headers.append('Set-Cookie', `google_oauth_state=; Path=/; HttpOnly; Secure; SameSite=Lax; Max-Age=0`);
  console.log(`CREATE_SESSION_REDIRECT: Clearing Google OAuth State Cookie.`);

  // 清除 google_flow_origin cookie
  headers.append('Set-Cookie', `google_flow_origin=; Path=/; HttpOnly; Secure; SameSite=Lax; Max-Age=0`);
  console.log(`CREATE_SESSION_REDIRECT: Clearing Google Flow Origin Cookie.`);

  headers.set('Location', redirectTo); // <--- 使用 redirectTo 参数
  console.log(`CREATE_SESSION_REDIRECT: Redirecting to: ${redirectTo}`);

  return new Response(null, { status: 302, headers: headers });
}

// 您需要实现这个 JWT 生成函数
async function generateJwtToken(email, userId, env) {
    // 确保您的 JWT_SECRET 在环境变量中
    const secret = env.JWT_SECRET;
    if (!secret) {
        throw new Error("JWT_SECRET environment variable not set.");
    }
    const header = {
        alg: "HS256",
        typ: "JWT"
    };
    const payload = {
        sub: userId,
        email: email,
        iat: Math.floor(Date.now() / 1000),
        exp: Math.floor(Date.now() / 1000) + (60 * 60 * 24 * 7) // 7 days expiry
    };
    const base64UrlEncode = (obj) => {
        const json = JSON.stringify(obj);
        const base64 = btoa(json);
        return base64.replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
    };
    const encodedHeader = base64UrlEncode(header);
    const encodedPayload = base64UrlEncode(payload);
    const data = `${encodedHeader}.${encodedPayload}`;
    // 使用 Web Crypto API 生成签名
    const key = await crypto.subtle.importKey(
        "raw",
        new TextEncoder().encode(secret),
        { name: "HMAC", hash: "SHA-256" },
        false,
        ["sign"]
    );
    const signature = await crypto.subtle.sign(
        "HMAC",
        key,
        new TextEncoder().encode(data)
    );
    const encodedSignature = base64UrlEncode(new Uint8Array(signature));
    return `${data}.${encodedSignature}`;
}

async function handleGoogle2FALogin(request, env) {
  const formData = await request.formData();
  const email = formData.get('email');
  const twoFactorCode = formData.get('twoFactorCode');

  if (!email || !twoFactorCode) {
      return new Response(renderTwoFactorVerificationPage(email, 'Missing email or 2FA code.'), {
          headers: { 'Content-Type': 'text/html' },
          status: 400,
      });
  }

  try {
      // 从数据库中获取用户，包括 2FA 密钥和状态
      const userQuery = 'SELECT id, email, two_factor_secret, two_factor_enabled FROM users WHERE email = ?';
      const user = await env.user_data.prepare(userQuery).bind(email).first();

      // 验证用户是否存在，2FA 是否启用，以及是否有密钥
      if (!user || !user.two_factor_enabled || !user.two_factor_secret) {
          console.error(`2FA bypass attempt for user ${email} or 2FA not enabled/secret missing.`);
          return new Response(renderTwoFactorVerificationPage(email, '2FA not enabled for this account or invalid user.'), {
              headers: { 'Content-Type': 'text/html' },
              status: 401,
          });
      }

      // 验证 TOTP 代码
      const isValid = await verifyTOTP(user.two_factor_secret, twoFactorCode);

      if (isValid) {
          console.log(`DEBUG: 2FA successful for Google user ${email}. Creating session.`);
          // 2FA 验证成功，创建会话并重定向到主页
          return await createSessionAndRedirect(user.email, user.id, env);
      } else {
          console.log(`DEBUG: Invalid 2FA code for Google user ${email}.`);
          // 2FA 验证失败，重新渲染 2FA 页面并显示错误
          return new Response(renderTwoFactorVerificationPage(email, 'Invalid 2FA code.'), {
              headers: { 'Content-Type': 'text/html' },
              status: 401,
          });
      }

  } catch (error) {
      console.error('Error during Google 2FA verification:', error);
      return new Response(renderTwoFactorVerificationPage(email, `Error during 2FA verification: ${error.message}`), {
          headers: { 'Content-Type': 'text/html' },
          status: 500,
      });
  }
}

