// --- 新增: 请求处理函数 handleSetPasswordRoute ---
async function handleSetPasswordRoute(request, env, loggedInUserEmail) {
  if (!loggedInUserEmail) {
    return Response.redirect(new URL('/login', request.url).toString(), 302);
  }

  if (request.method === 'GET') {
    return new Response(
      renderSetPasswordPage(null, loggedInUserEmail),   // null = no error
      { headers: { 'Content-Type': 'text/html' } }
    );
  }

  // ==================== POST ====================
  if (request.method === 'POST') {
    try {
      const formData = await request.formData();
      const password = (formData.get('password') || '').trim();
      const confirmPassword = (formData.get('confirm_password') || '').trim();

      // Validation
      if (!password || !confirmPassword) {
        return new Response(
          renderSetPasswordPage("Please enter both passwords.", loggedInUserEmail),
          { headers: { 'Content-Type': 'text/html' }, status: 400 }
        );
      }

      if (password !== confirmPassword) {
        return new Response(
          renderSetPasswordPage("Passwords do not match!", loggedInUserEmail),
          { headers: { 'Content-Type': 'text/html' }, status: 400 }
        );
      }

      if (password.length < 6) {
        return new Response(
          renderSetPasswordPage("Password must be at least 6 characters long.", loggedInUserEmail),
          { headers: { 'Content-Type': 'text/html' }, status: 400 }
        );
      }

      // TODO: Add your password hashing function here
      // const hashedPassword = await hashPassword(password);

      // For now, we'll store plain (replace with real hashing later)
      await env.user_data.prepare(`
        UPDATE users 
        SET password = ?, 
            password_set_status = 'set',
            approval_status = 'pending'
        WHERE email = ?
      `).bind(password, loggedInUserEmail).run();   // ← Change to hashedPassword when ready

      console.log(`Password set successfully for ${loggedInUserEmail}`);

      return Response.redirect(
        new URL('/pending-approval', request.url).toString(), 
        302
      );

    } catch (err) {
      console.error('Error in handleSetPasswordRoute POST:', err);
      return new Response(
        renderSetPasswordPage("Server error. Please try again.", loggedInUserEmail),
        { headers: { 'Content-Type': 'text/html' }, status: 500 }
      );
    }
  }

  return new Response('Method Not Allowed', { status: 405 });
}

