// --- New Handler for Admin Updating User Profile ---
async function handleAdminUpdateUserProfile(request, env, loggedInUserEmail, userRole) {
  if (request.method !== 'POST') {
      return new Response('Method Not Allowed', { status: 405 });
  }

  // Ensure the logged-in user is at least an 'admin' or 'superadmin'
  // This check is crucial for security.
  if (!loggedInUserEmail || (userRole !== 'admin' && userRole !== 'superadmin')) {
      console.warn(`Unauthorized attempt to update user profile by ${loggedInUserEmail} (Role: ${userRole})`);
      return new Response('Access Denied: You do not have permission to modify user profiles.', { status: 403 });
  }

  try {
      const formData = await request.formData();
      const userId = formData.get('id');
      const username = formData.get('username');
      const status = formData.get('status');
      const approval_status = formData.get('approval_status');
      const role = formData.get('role'); // Only present if superadmin is making the request
      const warning_count = parseInt(formData.get('warning_count'), 10);
      const warning_reason = formData.get('warning_reason');
      const profileImageFile = formData.get('profileImage');
      const deleteProfileImage = formData.get('deleteProfileImage') === 'true';

      if (!userId || !username || !status || !approval_status || isNaN(warning_count)) {
          return new Response('Missing required fields for user profile update', { status: 400 });
      }

      let updateQuery = 'UPDATE users SET username = ?, status = ?, approval_status = ?, warning_count = ?, warning_reason = ?';
      const bindValues = [username, status, approval_status, warning_count, warning_reason];

      // Only allow superadmin to change roles
      if (userRole === 'superadmin' && role) {
          updateQuery += ', role = ?';
          bindValues.push(role);
      } else if (userRole !== 'superadmin' && role && role !== 'user') {
          // If an admin tries to set a role other than 'user', reject it
          return new Response('Access Denied: You do not have permission to set this role.', { status: 403 });
      }


      if (deleteProfileImage) {
          updateQuery += ', profile_image = NULL';
      } else if (profileImageFile && profileImageFile.size > 0) {
          const arrayBuffer = await profileImageFile.arrayBuffer();
          const base64Image = btoa(
              new Uint8Array(arrayBuffer).reduce((data, byte) => data + String.fromCharCode(byte), '')
          );
          const imageDataUrl = `data:${profileImageFile.type};base64,${base64Image}`;
          updateQuery += ', profile_image = ?';
          bindValues.push(imageDataUrl);
      }

      updateQuery += ' WHERE id = ?';
      bindValues.push(userId);

      await env.user_data.prepare(updateQuery).bind(...bindValues).run();

      const redirectUrl = new URL('/admin', request.url);
      return Response.redirect(redirectUrl.toString(), 302);
  } catch (error) {
      console.error('Error updating user profile:', error);
      return new Response('Error updating user profile: ' + error.message, { status: 500 });
  }
}

// Function to generate a random 12-digit barcode
function generateRandomBarcode() {
  let barcode = '';
  for (let i = 0; i < 12; i++) {
    barcode += Math.floor(Math.random() * 10); // Append a random digit (0-9)
  }
  return barcode;
}

// handleAdminAddProductQuantity (MODIFIED)
async function handleAdminAddProductQuantity(request, env) {
  if (request.method !== 'POST') {
      return new Response('Method Not Allowed', { status: 405 });
  }

  try {
      const { document_id, amount } = await request.json();
      if (!document_id || isNaN(amount) || amount <= 0) {
          return new Response('Missing product ID or invalid amount', { status: 400 });
      }

      // First, update the quantity
      const updateQuantityQuery = 'UPDATE products SET quantity = quantity + ? WHERE document_id = ?';
      await env.user_info.prepare(updateQuantityQuery).bind(amount, document_id).run();

      // Second, check the new quantity and update status if necessary
      const checkQuantityQuery = 'SELECT quantity FROM products WHERE document_id = ?';
      const product = await env.user_info.prepare(checkQuantityQuery).bind(document_id).first();

      if (product && product.quantity > 0) {
          // If quantity is now greater than 0, ensure status is 'Available'
          // This handles cases where quantity was 0 and status was 'Borrowed' or 'Unavailable'
          const updateStatusQuery = 'UPDATE products SET status = ? WHERE document_id = ? AND status != ?';
          await env.user_info.prepare(updateStatusQuery).bind('Available', document_id, 'Available').run();
      }

      return new Response('Quantity added and status updated successfully', { status: 200 });
  } catch (err) {
      console.error("Error adding product quantity:", err);
      return new Response('Error adding product quantity: ' + err.message, { status: 500 });
  }
}

// handleAdminRemoveProductQuantity (MODIFIED)
async function handleAdminRemoveProductQuantity(request, env) {
  if (request.method !== 'POST') {
      return new Response('Method Not Allowed', { status: 405 });
  }

  try {
      const { document_id, amount } = await request.json();
      if (!document_id || isNaN(amount) || amount <= 0) {
          return new Response('Missing product ID or invalid amount', { status: 400 });
      }

      // Ensure quantity doesn't go below zero
      const checkQuery = 'SELECT quantity FROM products WHERE document_id = ?';
      const product = await env.user_info.prepare(checkQuery).bind(document_id).first();
      if (!product) {
          return new Response('Product not found.', { status: 404 });
      }
      if (product.quantity < amount) {
          return new Response('Cannot remove more than available quantity.', { status: 400 });
      }

      // First, update the quantity
      const updateQuantityQuery = 'UPDATE products SET quantity = quantity - ? WHERE document_id = ?';
      await env.user_info.prepare(updateQuantityQuery).bind(amount, document_id).run();

      // Second, check the new quantity and update status if necessary
      const newQuantity = product.quantity - amount; // Calculate the new quantity
      if (newQuantity <= 0) { // Use <= 0 to catch if it becomes exactly 0 or less
          // If quantity is now 0 or less, set status to 'Borrowed'
          // (consistent with handleBorrowItem setting to 'Borrowed' when quantity becomes 0)
          const updateStatusQuery = 'UPDATE products SET status = ? WHERE document_id = ? AND status != ?';
          await env.user_info.prepare(updateStatusQuery).bind('Borrowed', document_id, 'Borrowed').run();
      }

      return new Response('Quantity removed and status updated successfully', { status: 200 });
  } catch (err) {
      console.error("Error removing product quantity:", err);
      return new Response('Error removing product quantity: ' + err.message, { status: 500 });
  }
}

// NEW: Function to check and send reminders for overdue or soon-due items
async function checkAndSendReminders(env) {
  const currentTime = Date.now();
  
  // 使用文件顶部定义的实际常量
  const borrowPeriodMs = BORROW_PERIOD_DAYS * 24 * 60 * 60 * 1000;
  const compulsoryReminderMs = COMPULSORY_REMINDER_DAYS * 24 * 60 * 60 * 1000; // 强制提醒阈值
  const reminderCooldownMs = REMINDER_COOLDOWN_MS; // 冷却时间，虽然不直接用于生成新通知，但保留以供参考

  console.log("--- Starting checkAndSendReminders (V3 - Enhanced Logging) at", new Date(currentTime).toISOString(), "---");
  console.log(`  Constants: BORROW_PERIOD_DAYS=${BORROW_PERIOD_DAYS} (${borrowPeriodMs}ms), COMPULSORY_REMINDER_DAYS=${COMPULSORY_REMINDER_DAYS} (${compulsoryReminderMs}ms)`);
  
  try {
    // 查询所有未归还的借阅物品
    const query = `
      SELECT br.id, br.user_email, br.borrow_time, br.last_reminder_sent_at, p.name AS product_name
      FROM borrowing_records br
      JOIN products p ON br.document_id = p.document_id
      WHERE br.return_time IS NULL
    `;
    const { results: borrowedItems } = await env.user_info.prepare(query).all();
    console.log(`  Found ${borrowedItems.length} active borrowed items.`);
    
    if (borrowedItems.length === 0) {
      console.log("  No active borrowed items found. Exiting reminder check.");
      return;
    }

    for (const item of borrowedItems) {
      const borrowTime = item.borrow_time;
      const dueDate = borrowTime + borrowPeriodMs;
      const timeRemaining = dueDate - currentTime; // 剩余时间（毫秒，如果逾期则为负数）
      
      const isOverdue = currentTime > dueDate;
      // 强制提醒条件：
      // 1. 剩余时间小于等于强制提醒阈值 (例如，到期前 3 天内)
      // 2. 剩余时间必须大于 0 (确保不是已经逾期)
      const isCompulsoryReminderTime = (timeRemaining <= compulsoryReminderMs) && (timeRemaining > 0); 
      
      console.log(`\n--- Processing item: "${item.product_name}" (Record ID: ${item.id}, User: ${item.user_email}) ---`);
      console.log(`  Borrow Time: ${new Date(borrowTime).toISOString()} (Unix Timestamp: ${borrowTime})`);
      console.log(`  Due Date: ${new Date(dueDate).toISOString()} (Unix Timestamp: ${dueDate})`);
      console.log(`  Current Time: ${new Date(currentTime).toISOString()} (Unix Timestamp: ${currentTime})`);
      console.log(`  Calculated Time Remaining (ms): ${timeRemaining}`);
      console.log(`  Is Overdue: ${isOverdue}`);
      console.log(`  Is Compulsory Reminder Time (within ${COMPULSORY_REMINDER_DAYS} days): ${isCompulsoryReminderTime}`);
      
      let notificationMessage = null;
      
      if (isOverdue) {
          const timeOverdue = currentTime - dueDate;
          const daysOverdue = Math.floor(timeOverdue / (24 * 60 * 60 * 1000));
          const hoursOverdue = Math.floor((timeOverdue % (24 * 60 * 60 * 1000)) / (60 * 60 * 1000));
          const minutesOverdue = Math.floor((timeOverdue % (60 * 60 * 1000)) / (60 * 1000));
          let overdueMessagePart = '';
          if (daysOverdue > 0) overdueMessagePart += `${daysOverdue} day(s) `;
          if (hoursOverdue > 0) overdueMessagePart += `${hoursOverdue} hour(s) `;
          if (minutesOverdue > 0 || (daysOverdue === 0 && hoursOverdue === 0 && minutesOverdue > 0)) overdueMessagePart += `${minutesOverdue} minute(s)`;
          
          notificationMessage = `⚠️ Overdue Alert: Your borrowed item "${item.product_name}" is overdue by ${overdueMessagePart.trim()}! Please return it immediately.`;
          console.log(`  Action: Condition met: Is Overdue. Generating message: "${notificationMessage}"`);

      } else if (isCompulsoryReminderTime) {
          const daysRemaining = Math.ceil(timeRemaining / (24 * 60 * 60 * 1000));
          const hoursRemaining = Math.floor((timeRemaining % (24 * 60 * 60 * 1000)) / (60 * 60 * 1000));
          const minutesRemaining = Math.floor((timeRemaining % (60 * 60 * 1000)) / (60 * 1000));
          let reminderMessagePart = '';
          if (daysRemaining > 0) reminderMessagePart += `${daysRemaining} day(s) `;
          if (hoursRemaining > 0) reminderMessagePart += `${hoursRemaining} hour(s) `;
          if (minutesRemaining > 0 || (daysRemaining === 0 && hoursRemaining === 0 && minutesRemaining > 0)) reminderMessagePart += `${minutesRemaining} minute(s)`;
          
          notificationMessage = `🚨 Action Required: Your borrowed item "${item.product_name}" is due in ${reminderMessagePart.trim()}! Please return it promptly.`;
          console.log(`  Action: Condition met: Is Compulsory Reminder Time. Generating message: "${notificationMessage}"`);

      } else {
          console.log("  No specific notification condition met for this item (not overdue and not in compulsory reminder window).");
      }

      if (notificationMessage) {
          // 搜索此用户和产品的所有现有提醒或逾期通知
          const findExistingNotifQuery = `
              SELECT id, message, read, timestamp
              FROM notifications
              WHERE user_email = ?
              AND (
                  message LIKE '⚠️ Overdue Alert: Your borrowed item "%${escapeSqliteLike(item.product_name)}%"%' OR
                  message LIKE '🚨 Action Required: Your borrowed item "%${escapeSqliteLike(item.product_name)}%"%'
              )
              ORDER BY timestamp DESC LIMIT 1
          `;
          const existingNotif = await env.user_data.prepare(findExistingNotifQuery)
              .bind(item.user_email)
              .first();
          
          if (existingNotif) {
              console.log(`  Found existing notification (ID: ${existingNotif.id}, Read: ${existingNotif.read ? 'true' : 'false'}). Updating its message, timestamp, and marking as unread.`);
              // 如果存在相关提醒/逾期通知，则更新并强制设置为未读
              const updateNotifQuery = 'UPDATE notifications SET message = ?, timestamp = ?, read = 0 WHERE id = ?';
              await env.user_data.prepare(updateNotifQuery).bind(notificationMessage, currentTime, existingNotif.id).run();
              console.log(`  Notification (ID: ${existingNotif.id}) updated and reactivated for item "${item.product_name}" for user ${item.user_email}.`);
          } else {
              console.log("  No existing relevant notification found. Creating a NEW notification.");
              // 如果没有相关提醒/逾期通知，则创建新的
              await createNotification(env, item.user_email, notificationMessage);
              console.log(`  Created new notification for item "${item.product_name}" to ${item.user_email}`);
          }
          
          // 无论更新还是创建，都更新借阅记录中的 last_reminder_sent_at
          const updateBorrowRecordQuery = 'UPDATE borrowing_records SET last_reminder_sent_at = ? WHERE id = ?';
          await env.user_info.prepare(updateBorrowRecordQuery).bind(currentTime, item.id).run();
          console.log(`  Updated last_reminder_sent_at for borrowing record ID: ${item.id}.`);
      } else {
          // 如果没有生成通知消息（即物品不再逾期或不在强制提醒窗口），则将所有相关的未读提醒/逾期通知标记为已读。
          const findAndMarkIrrelevantNotifsQuery = `
              SELECT id
              FROM notifications
              WHERE user_email = ?
              AND (
                  message LIKE '⚠️ Overdue Alert: Your borrowed item "%${escapeSqliteLike(item.product_name)}%"%' OR
                  message LIKE '🚨 Action Required: Your borrowed item "%${escapeSqliteLike(item.product_name)}%"%'
              )
              AND read = 0
          `;
          const { results: irrelevantNotifs } = await env.user_data.prepare(findAndMarkIrrelevantNotifsQuery)
              .bind(item.user_email)
              .all();
          
          if (irrelevantNotifs.length > 0) {
              const idsToMarkRead = irrelevantNotifs.map(n => n.id);
              const placeholders = idsToMarkRead.map(() => '?').join(', ');
              const markReadQuery = `UPDATE notifications SET read = 1 WHERE id IN (${placeholders})`;
              await env.user_data.prepare(markReadQuery).bind(...idsToMarkRead).run();
              console.log(`  Marked ${idsToMarkRead.length} irrelevant notifications as read for item "${item.product_name}".`);
          } else {
              console.log("  No irrelevant notifications (overdue/compulsory) to mark as read for this item.");
          }
      }
      console.log(`--- Finished processing item: "${item.product_name}" ---\n`);
    }
    console.log("--- Finished checkAndSendReminders. ---");
  } catch (err) {
    console.error('Error in checkAndSendReminders (outer catch block):', err);
  }
}

